namespace sv_315d930132314689b8df25af51559fba.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 30),
            new(2, "Margherita Pizza", "Neapolitan pizza with San Marzano tomatoes, mozzarella, and fresh basil.", 45),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken chunks in a creamy spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach puree with cubes of paneer in aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork on corn tortillas with pineapple, cilantro, and onion.", 55),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Churros", "Fried dough pastry coated in cinnamon sugar, served with chocolate sauce.", 25),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
            return recipes;

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_315d930132314689b8df25af51559fba.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<h2>Recipes</h2>

@if (_error is not null)
{
    <div class="alert alert-danger">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><small><em>Refreshing…</em></small></p>
    }

    <ul>
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes!.OrderByDescending(r => r.Id),
            "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes!
        };

    protected override Task OnParametersSetAsync()
    {
        // Only reload when cuisine changes, not when sort changes
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }
        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, _loadCts.Token);
            _recipes = results;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (_disposeCts.IsCancellationRequested)
        {
            // Component is disposing — do nothing
        }
        catch (OperationCanceledException)
        {
            // Superseded by a newer load — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong loading recipes. Please try again.";
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

